// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedForecastIndex, setSelectedForecastIndex] = useState<number>(0);
  const normalizedUnit = (props.unit ?? 'C').toUpperCase();
  const [isMetricView, setIsMetricView] = useState<boolean>(normalizedUnit === 'C');

  useEffect(() => {
    setIsMetricView(normalizedUnit === 'C');
  }, [normalizedUnit]);

  const conditionIcon = useMemo(() => {
    const normalized = props.condition.toLowerCase();
    if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('hail')) return '❄️';
    if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
    if (normalized.includes('wind')) return '💨';
    return '🌤️';
  }, [props.condition]);

  const displayedUnit = isMetricView ? 'C' : 'F';
  const normalizedForecast = useMemo(() => {
    if (!Array.isArray(props.forecast)) return [];
    const sliced = props.forecast.slice(0, 5);
    if (sliced.length === 5) return sliced;
    return [
      ...sliced,
      ...Array.from({ length: 5 - sliced.length }, () => ({ day: '—', icon: '🌡️', high: undefined, low: undefined })),
    ];
  }, [props.forecast]);
  const hasForecast = normalizedForecast.length > 0;
  const hasInvalidForecastLength = Array.isArray(props.forecast) && props.forecast.length !== 5;
  const safeForecastIndex = hasForecast
    ? Math.min(selectedForecastIndex, normalizedForecast.length - 1)
    : 0;
  const selectedForecast = hasForecast ? normalizedForecast[safeForecastIndex] : null;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center" wrap>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Now in</Text>
                <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              </Stack>
              <Badge variant="primary">{displayedUnit}° view</Badge>
            </Row>

            <Row justify="between" align="center" wrap>
              <Stack gap="var(--ggui-spacing-1)">
                <Text
                  size="4xl"
                  weight="bold"
                  color="var(--ggui-color-primary-600)"
                >
                  {props.temperature}°{displayedUnit}
                </Text>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Text size="2xl" is="span" aria-label={props.condition}>{conditionIcon}</Text>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurface)">{props.condition}</Text>
                </Row>
              </Stack>

              <Stack gap="var(--ggui-spacing-2)">
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplets" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Row>
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
                  <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
                </Row>
              </Stack>
            </Row>

            <Divider margin="var(--ggui-spacing-2)" />

            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3} color="var(--ggui-color-onSurfaceVariant)">
                5-Day Forecast
              </Heading>

              {!hasForecast ? (
                <Alert variant="info" title="No forecast data">
                  Forecast information is currently unavailable.
                </Alert>
              ) : (
                <Stack gap="var(--ggui-spacing-2)">
                  {hasInvalidForecastLength && (
                    <Alert variant="warning" title="Forecast normalized">
                      Received {props.forecast.length} entries; showing a normalized 5-day strip.
                    </Alert>
                  )}
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {normalizedForecast.map((dayForecast, index) => (
                      <Button
                        key={`${dayForecast.day || 'day'}-${index}`}
                        variant={safeForecastIndex === index ? 'secondary' : 'ghost'}
                        size="sm"
                        onClick={() => setSelectedForecastIndex(index)}
                      >
                        <Stack align="center" gap="var(--ggui-spacing-1)">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {dayForecast.day || '—'}
                          </Text>
                          <Text size="xl" is="span" aria-label={dayForecast.day ? `${dayForecast.day} ${props.condition}` : 'Weather icon'}>{dayForecast.icon || '🌡️'}</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurface)">
                            {dayForecast.high ?? '—'}°{displayedUnit} / {dayForecast.low ?? '—'}°{displayedUnit}
                          </Text>
                        </Stack>
                      </Button>
                    ))}
                  </Row>
                </Stack>
              )}

              {selectedForecast && (
                <Card padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Selected: {selectedForecast.day || '—'} • High {selectedForecast.high ?? '—'}°{displayedUnit} • Low {selectedForecast.low ?? '—'}°{displayedUnit}
                  </Text>
                </Card>
              )}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

