// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number | null>(null);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false, satisfaction: false });

  const totalSteps = 4;
  const maxComments = 500;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const nameError = touched.name && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = touched.email && email.trim().length === 0
    ? 'Email is required.'
    : touched.email && !emailRegex.test(email.trim())
      ? 'Please enter a valid email address.'
      : '';
  const normalizedSatisfactionOptions = useMemo(() => {
    const labels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels.slice(0, 5) : [];
    return labels.map((label, index) => ({
      value: String(index + 1),
      label,
      description: `Rating ${index + 1}`
    }));
  }, [props.satisfactionLabels]);

  const hasNoSatisfactionLabels = normalizedSatisfactionOptions.length === 0;
  const hasMismatchedSatisfactionLabels = Array.isArray(props.satisfactionLabels) && props.satisfactionLabels.length !== 5;

  const sanitizedFeatureOptions = useMemo(() => {
    const raw = Array.isArray(props.featureOptions) ? props.featureOptions : [];
    const seen = new Set<string>();
    return raw
      .map((item) => item.trim())
      .filter((item) => item.length > 0)
      .filter((item) => {
        if (seen.has(item)) return false;
        seen.add(item);
        return true;
      });
  }, [props.featureOptions]);

  const satisfactionError = touched.satisfaction && satisfaction === null ? 'Please select a satisfaction rating.' : '';

  const isStep1Valid = name.trim().length > 0 && emailRegex.test(email.trim());
  const isStep2Valid = satisfaction !== null && satisfaction >= 1 && satisfaction <= 5 && normalizedSatisfactionOptions.length === 5;
  const canGoNext = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;

  const progressValue = Math.round(((step - 1) / (totalSteps - 1)) * 100);

  const handleNext = () => {
    if (step === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!isStep1Valid) return;
    }
    if (step === 2) {
      setTouched((prev) => ({ ...prev, satisfaction: true }));
      if (!isStep2Valid) return;
    }
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  };

  const handleBack = () => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    if (checked) {
      setFeatures((prev) => (prev.includes(feature) ? prev : [...prev, feature]));
      return;
    }
    setFeatures((prev) => prev.filter((item) => item !== feature));
  };

  const handleSubmit = () => {
    if (!(satisfaction !== null && satisfaction >= 1 && satisfaction <= 5)) return;
    const validFeatureSet = new Set(sanitizedFeatureOptions);
    const filteredFeatures = features.filter((feature) => validFeatureSet.has(feature));
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features: filteredFeatures,
      comments,
    };
    if ((props as unknown as { onSubmit?: (data: ActionSubmitPayload) => void }).onSubmit) {
      (props as unknown as { onSubmit: (data: ActionSubmitPayload) => void }).onSubmit(payload);
      return;
    }
    submit(payload);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Tell us about you</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction rating</Heading>
                {hasNoSatisfactionLabels ? (
                  <Alert variant="warning" title="No satisfaction labels available">
                    Satisfaction options are currently unavailable. Please provide five labels to continue.
                  </Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-3)">
                    {hasMismatchedSatisfactionLabels && (
                      <Alert variant="info" title="Satisfaction labels adjusted">
                        We expected exactly 5 labels. Please provide five satisfaction labels to continue.
                      </Alert>
                    )}
                    <RadioGroup
                      label="How satisfied are you?"
                      value={satisfaction === null ? '' : String(satisfaction)}
                      onChange={(value) => {
                        const parsed = Number(value);
                        setSatisfaction(parsed >= 1 && parsed <= 5 ? parsed : null);
                      }}
                      error={satisfactionError}
                      options={normalizedSatisfactionOptions}
                    />
                  </Stack>
                )}
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature interests</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Select all features you are interested in.
                </Text>
                <Stack gap="var(--ggui-spacing-3)">
                  {sanitizedFeatureOptions.length === 0 ? (
                    <Alert variant="info" title="No features available">
                      There are currently no feature options to choose from.
                    </Alert>
                  ) : (
                    sanitizedFeatureOptions.map((feature, index) => (
                      <Checkbox
                        key={`${index}-${feature}`}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => handleFeatureToggle(feature, checked)}
                      />
                    ))
                  )}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={comments}
                  onChange={setComments}
                  maxLength={maxComments}
                  showCount
                  rows={6}
                  helperText="Share any additional thoughts."
                  placeholder="Type your comments here..."
                />
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional comments & review</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={comments}
                  onChange={setComments}
                  maxLength={maxComments}
                  showCount
                  rows={6}
                  helperText="Share any additional thoughts."
                  placeholder="Type your comments here..."
                />
                <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                      <Text>{name || '—'}</Text>
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                      <Text>{email || '—'}</Text>
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                      <Text>
                        {satisfaction !== null && normalizedSatisfactionOptions[satisfaction - 1]
                          ? `${satisfaction} - ${normalizedSatisfactionOptions[satisfaction - 1].label}`
                          : '—'}
                      </Text>
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features</Text>
                      {features.length === 0 ? (
                        <Text>None selected</Text>
                      ) : (
                        <Row gap="var(--ggui-spacing-2)" wrap>
                          {features.map((feature, index) => (
                            <Tag key={`${index}-${feature}`} variant="primary">
                              {feature}
                            </Tag>
                          ))}
                        </Row>
                      )}
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                      <Text>{comments.trim().length > 0 ? comments : 'No comments provided.'}</Text>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center" gap="var(--ggui-spacing-3)" wrap>
              <Button variant="outline" onClick={handleBack} disabled={step === 1} fullWidth>
                Back
              </Button>
              {step < totalSteps ? (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext} fullWidth>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit} fullWidth>
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

