    const previousTask = tasksState.find((task) => task.id === taskId);
    if (!previousTask) return;
    setIsSaving(true);
    setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumnId } : task)));
    try {
      taskUpdate({ action: 'move', taskId, data: { column: nextColumnId, title: previousTask.title, priority: previousTask.priority, assignee: previousTask.assignee, dueDate: previousTask.dueDate } });
      setUiError('');
    } catch (_error) {
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: previousTask.column } : task)));
      setUiError('Failed to move task. Please try again.');
    } finally {
      setIsSaving(false);
    }
  }, [taskUpdate, tasksState, validColumnIds]);

  const saveEditTask = useCallback((taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) return;
