    setIsSaving(true);
    setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: trimmed } : task)));
    setEditingTaskId('');
    setEditingTitle('');
    try {
      taskUpdate({ action: 'edit', taskId, data: { column: previousTask.column, title: trimmed, priority: previousTask.priority, assignee: previousTask.assignee, dueDate: previousTask.dueDate } });
      setUiError('');
    } catch (_error) {
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: previousTask.title } : task)));
