      priority: newTaskPriority,
      assignee: 'NA',
      column: 'todo',
      dueDate: undefined,
    } as const;
    setIsSaving(true);
    setTasksState((prev) => [...prev, createdTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId('');
    try {
      taskUpdate({ action: 'create', taskId: createdId, data: { column: 'todo', title: createdTask.title, priority: createdTask.priority, assignee: createdTask.assignee, dueDate: createdTask.dueDate } });
      setUiError('');
    } catch (_error) {
      setTasksState((prev) => prev.filter((task) => task.id !== createdId));
      setUiError('Failed to create task.');
    } finally {
      setIsSaving(false);
