const getCategoryColor = (category: string): string => {
  const key = category.toLowerCase();
  if (key.includes('noble')) return 'var(--ggui-color-primary-200)';
  if (key.includes('halogen')) return 'var(--ggui-color-warning-200)';
  if (key.includes('alkali metal')) return 'var(--ggui-color-error-200)';
  if (key.includes('alkaline earth')) return 'var(--ggui-color-warning-100)';
  if (key.includes('transition')) return 'var(--ggui-color-primary-100)';
  if (key.includes('post-transition')) return 'var(--ggui-color-info-100)';
  if (key.includes('metalloid')) return 'var(--ggui-color-success-100)';
  if (key.includes('nonmetal')) return 'var(--ggui-color-success-200)';
  if (key.includes('lanthanide')) return 'var(--ggui-color-info-200)';
  if (key.includes('actinide')) return 'var(--ggui-color-error-100)';
  return 'var(--ggui-color-surfaceVariant)';
};

