interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<StreamTyping | null>(null);
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const [isInitializing, setIsInitializing] = useState<boolean>(true);
  const [sendError, setSendError] = useState<string>('');

  useEffect(() => {
    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest) {
      setTypingState(typing.latest);
    }
  }, [typing.latest]);

  useLayoutEffect(() => {
    const frame = setTimeout(() => {
      if (scrollRef.current) {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
      setIsInitializing(false);
    }, 0);
    return () => clearTimeout(frame);
  }, [allMessages]);

  const groupedMessages = useMemo(() => {
    const source = allMessages ?? [];
    const groups: Array<{ sender: string; items: Array<{ text: string; timestamp: string }> }> = [];

    source.forEach((item) => {
      const sender = item.sender ?? 'Unknown';
      const text = item.text ?? '';
      const timestamp = item.timestamp ?? '';
      const lastGroup = groups[groups.length - 1];

      if (lastGroup && lastGroup.sender === sender) {
        lastGroup.items.push({ text, timestamp });
      } else {
        groups.push({ sender, items: [{ text, timestamp }] });
      }
    });

    return groups;
  }, [allMessages]);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) {
      return;
    }
    try {
      const now = new Date().toISOString();
      sendMessage({ text: trimmed, timestamp: now });
      setAllMessages((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp: now }]);
      setDraft('');
      setSendError('');
    } catch (_error) {
      setSendError('Message failed to send. Please try again.');
    }
  }, [draft, props.currentUser, sendMessage]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-4)"
        shadow="none"
        radius="md"
      >
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Row gap="var(--ggui-spacing-3)" align="center">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary">{String(props.participantCount)} participants</Badge>
            </Row>
            {typingState && typingState.active && typingState.sender && typingState.sender !== props.currentUser ? (
              <Text
                variant="bodySmall"
                color="var(--ggui-color-onSurfaceVariant)"
                is="div"
                role="status"
                aria-live="polite"
              >
                {typingState.sender} is typing...
              </Text>
            ) : null}
          </Row>

          <Box
            borderRadius="var(--ggui-shape-radius-md)"
            background="var(--ggui-color-surface)"
            padding="var(--ggui-spacing-3)"
            ref={scrollRef}
            role="log"
            aria-live="polite"
            aria-relevant="additions"
            style={{ maxHeight: '60vh', overflowY: 'auto' }}
          >
              <Stack gap="var(--ggui-spacing-3)">
                {groupedMessages.length === 0 ? (
                  <Text align="center" color="var(--ggui-color-onSurfaceVariant)">
                    No messages yet.
                  </Text>
                ) : (
                  groupedMessages.map((group, groupIndex) => {
                    const isCurrentUser = group.sender === props.currentUser;
                    return (
                      <Stack
                        key={`${group.sender}-${groupIndex}` }
                        gap="var(--ggui-spacing-1)"
                        align={isCurrentUser ? 'end' : 'start'}
                      >
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {group.sender}
                        </Text>
                        {group.items.map((item, itemIndex) => (
                          <Box
                            key={`${group.sender}-${groupIndex}-${itemIndex}` }
                            padding="var(--ggui-spacing-2)"
                            background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                            borderRadius="var(--ggui-shape-radius-md)"
                          >
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text color={isCurrentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>
                                {item.text}
                              </Text>
                              <Text
                                variant="caption"
                                color={isCurrentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}
                                align={isCurrentUser ? 'right' : 'left'}
                              >
                                {item.timestamp ? new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                              </Text>
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    );
                  })
                )}
              </Stack>
            </Box>

          <Divider margin="var(--ggui-spacing-1)" />
          {sendError ? (
            <Alert variant="error" title="Send failed">
              {sendError}
            </Alert>
          ) : null}
          {isInitializing ? (
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Spinner size={16} color="var(--ggui-color-primary-600)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Connecting to chat...
              </Text>
            </Row>
          ) : null}
          <Box
            is="form"
            onSubmit={(event: React.FormEvent<HTMLFormElement>) => {
              event.preventDefault();
              handleSend();
            }}
          >
            <Row gap="var(--ggui-spacing-2}" align="end">
              <Box padding="0" margin="0" background="transparent" borderRadius="0" style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type a message..."
                  value={draft}
                  onChange={setDraft}
                />
              </Box>
              <Button
                variant="primary"
                disabled={!draft.trim()}
                type="submit"
              >
                Send
              </Button>
            </Row>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

