              {marketStatusLabel}
            </Badge>
          </Row>
        </Box>

        {!marketStatus.latest && marketStatus.all.length === 0 ? (
          <Alert variant="warning" title="Connection status">
            Waiting for live market status stream…
          </Alert>
        ) : null}
        {streamError ? (
          <Alert variant="warning" title="Live update issue">
            {streamError}
          </Alert>
        ) : null}

        {isLoading ? (
          <Card padding="var(--ggui-spacing-6)" border>
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Spinner size={24} color="var(--ggui-color-primary-600)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Loading market data...
              </Text>
            </Stack>
          </Card>
        ) : stocksState.length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" border>
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No stock data available.
              </Text>
            </Stack>
          </Card>
        ) : (
          <Box>
            <CardGrid columns={{ sm: 1, lg: 3 }} gap={16}>
              {stocksState.map((stock, index) => {
                const isPositive = (stock.change || 0) >= 0;
                const trendColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
                const symbol = stock.symbol || `stock-${index}`;
                const isFlashing = flashMap[symbol] === true;

                return (
                  <Card
                    key={symbol}
                    padding="var(--ggui-spacing-4)"
                    border
                    shadow={isFlashing ? 'md' : 'sm'}
                  >
                    <Box
                      padding="var(--ggui-spacing-1)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={isFlashing ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)'}
                      style={{
                        border: `1px solid ${trendColor}`,
                        animation: isFlashing ? 'ggui-fadeIn 600ms ease-out' : 'none',
                        transition: 'background-color 300ms ease-out, border-color 300ms ease-out',
                      }}
                    >
                      <Stack gap="var(--ggui-spacing-2)">
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                        {stock.symbol || '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name || 'Unknown Company'}
                      </Text>
                      <Text
                        size="xl"
                        weight="semibold"
                        color={isFlashing ? 'var(--ggui-color-primary-700)' : 'var(--ggui-color-onSurface)'}
                      >
                        ${Number(stock.price || 0).toFixed(2)}
                      </Text>
                      <Row justify="between" align="center">
                        <Text variant="bodySmall" color={trendColor}>
                          {isPositive ? '+' : ''}{Number(stock.change || 0).toFixed(2)}
                        </Text>
                        <Text
                          variant="bodySmall"
                          color={trendColor}
                          weight="medium"
                          aria-label={`Trend ${isPositive ? 'up' : 'down'} ${isPositive ? '+' : ''}${Number(stock.changePercent || 0).toFixed(2)} percent`}
                        >
                          {isPositive ? '▲' : '▼'} {isPositive ? '+' : ''}{Number(stock.changePercent || 0).toFixed(2)}%
                        </Text>
                      </Row>
                      </Stack>
                    </Box>
                  </Card>
                );
              })}
            </CardGrid>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile.email ?? '');
  const defaultAvatar = useMemo(() => {
    if (props.initialProfile.avatar) return props.initialProfile.avatar;
    if (props.avatarOptions.length > 0) return props.avatarOptions[0];
    return '🙂';
  }, [props.initialProfile.avatar, props.avatarOptions]);
  const [avatar, setAvatar] = useState<string>(defaultAvatar);
  const [role, setRole] = useState<string>(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
  const [showSuccess, setShowSuccess] = useState<boolean>(false);
  const [submitError, setSubmitError] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const stepHeadingRef = useRef<HTMLHeadingElement | null>(null);

  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const stepOneValid = useMemo(() => name.trim().length > 0 && email.trim().length > 0 && isEmailValid, [name, email, isEmailValid]);
  const roleOptions = useMemo(
    () => (props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((item) => ({ value: item, label: item })),
    [props.roleOptions]
  );
  const allowedRoles = useMemo(() => roleOptions.map((item) => item.value), [roleOptions]);
  const stepTwoValid = useMemo(() => allowedRoles.includes(role), [role, allowedRoles]);
  const canProceed = step === 1 ? stepOneValid : step === 2 ? stepTwoValid : true;
  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  useEffect(() => {
    stepHeadingRef.current?.focus();
  }, [step]);


  const goNext = useCallback(() => {
    if (!canProceed) return;
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canProceed]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const onCompleteSetup = useCallback(() => {
    if (!stepOneValid || !stepTwoValid || isSubmitting) return;
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    setSubmitError('');
    setIsSubmitting(true);
    try {
      complete(payload);
      setShowSuccess(true);
    } catch (error) {
      setSubmitError(error instanceof Error ? error.message : 'Failed to complete setup. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  }, [stepOneValid, stepTwoValid, isSubmitting, name, email, avatar, role, emailNotifications, theme, complete]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={1}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" showLabel />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="md" border radius="lg">
          <Box>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Profile Setup</Heading>
                <Input
                  label="Name"
                  placeholder="Enter your name"
                  value={name}
                  onChange={setName}
                  required
                  error={name.trim().length === 0 ? 'Name is required.' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="you@example.com"
                  value={email}
                  onChange={setEmail}
                  required
                  error={email.trim().length > 0 && !isEmailValid ? 'Enter a valid email address.' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose Avatar</Text>
                  <RadioGroup
                    label="Avatar options"
                    value={avatar}
                    onChange={setAvatar}
                    direction="horizontal"
                    options={(props.avatarOptions.length > 0 ? props.avatarOptions : ['🙂', '😎', '🚀', '🎨']).slice(0, 4).map((emoji) => ({
                      value: emoji,
                      label: `Select avatar ${emoji}`
                    }))}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Selected: {avatar}</Text>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={roleOptions}
                  error={role.trim().length === 0 ? 'Role is required.' : undefined}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Row justify="between" align="center">
                  <Text variant="label">Theme preference</Text>
                  <Row gap="var(--ggui-spacing-2)">
                    <Button
                      variant={theme === 'light' ? 'primary' : 'outline'}
                      size="sm"
                      onClick={() => setTheme('light')}
                    >
                      Light
                    </Button>
                    <Button
                      variant={theme === 'dark' ? 'primary' : 'outline'}
                      size="sm"
                      onClick={() => setTheme('dark')}
                    >
                      Dark
                    </Button>
                  </Row>
                </Row>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text size="xl">{avatar}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Confirm your details">If everything looks good, click Complete Setup.</Alert>
                {submitError && <Alert variant="error" title="Submission failed">{submitError}</Alert>}
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={goBack} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 ? (
              <Button variant="primary" onClick={goNext} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={goBack}>Go Back</Button>
                <Button variant="primary" onClick={onCompleteSetup} disabled={!stepOneValid || !stepTwoValid || isSubmitting} loading={isSubmitting}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
      <Toast
        visible={showSuccess}
        variant="success"
        title="Setup complete"
        message="Your onboarding data was submitted successfully."
        onClose={() => setShowSuccess(false)}
        duration={3000}
      />
    </Container>

  );
}
